post_crear_productora.codigo:
fetch('http://localhost:4000/api/productora', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    nombre: 'Paramount Pictures',
    slogan: 'Summon the Gods',
    descripcion: 'Productora americana fundada en 1912'
  })
})
  .then(response => response.json())
  .then(data => console.log(data))
  .catch(error => console.error('Error:', error));

